"""
PEP 563 Transformer for handling circular imports.

This module provides a LibCST transformer that applies PEP 563 (postponed
evaluation of annotations) to resolve circular import issues that can arise
when applying type annotations. It:

1. Adds `from __future__ import annotations` at the top of the file
2. Moves newly added type imports into an `if TYPE_CHECKING:` block
3. Ensures `TYPE_CHECKING` is imported from `typing`

This allows type annotations to be used without causing runtime circular
imports, since the imports only execute during type checking.
"""
from typing import Dict, List, Optional, Sequence, Set, Union

import libcst as cst
from libcst.helpers import get_full_name_for_node


class GatherImportsBeforeTransform(cst.CSTVisitor):
    """Collects all imports present in the module before transformation."""

    def __init__(self) -> None:
        self.module_imports: Set[str] = set()
        self.from_imports: Dict[str, Set[str]] = {}

    def visit_Import(self, node: cst.Import) -> None:
        if isinstance(node.names, cst.ImportStar):
            return
        for name in node.names:
            module_name = get_full_name_for_node(name.name)
            if module_name:
                self.module_imports.add(module_name)

    def visit_ImportFrom(self, node: cst.ImportFrom) -> None:
        module = get_full_name_for_node(node.module) if node.module else ""
        if isinstance(node.names, cst.ImportStar):
            self.from_imports.setdefault(module, set()).add("*")
            return
        for alias in node.names:
            name = get_full_name_for_node(alias.name)
            if name:
                self.from_imports.setdefault(module, set()).add(name)


class GatherNewImports(cst.CSTVisitor):
    """Identifies imports that were added after transformation."""

    # Modules that should not be moved to TYPE_CHECKING block
    # These are runtime-required typing modules
    RUNTIME_TYPING_MODULES = frozenset(
        {
            "typing",
            "typing_extensions",
            "collections.abc",
        }
    )

    def __init__(
        self,
        original_module_imports: Set[str],
        original_from_imports: Dict[str, Set[str]],
    ) -> None:
        self.original_module_imports = original_module_imports
        self.original_from_imports = original_from_imports
        self.new_from_imports: Dict[str, List[cst.ImportAlias]] = {}
        self.import_nodes_to_modify: List[cst.ImportFrom] = []

    def visit_ImportFrom(self, node: cst.ImportFrom) -> None:
        module = get_full_name_for_node(node.module) if node.module else ""

        # Skip __future__ imports - they must stay at module level
        if module == "__future__":
            return

        # Skip runtime typing modules - they must stay at module level
        if module in self.RUNTIME_TYPING_MODULES:
            return

        if isinstance(node.names, cst.ImportStar):
            return

        original_names = self.original_from_imports.get(module, set())

        # Find which imports in this statement are new
        new_aliases: List[cst.ImportAlias] = []
        for alias in node.names:
            name = get_full_name_for_node(alias.name)
            if name and name not in original_names:
                new_aliases.append(alias)

        if new_aliases:
            self.new_from_imports.setdefault(module, []).extend(new_aliases)
            self.import_nodes_to_modify.append(node)


class PEP563Transformer(cst.CSTTransformer):
    """
    Transforms a module to use PEP 563 postponed annotations.

    This transformer:
    1. Ensures `TYPE_CHECKING` is imported from `typing`
    2. Moves newly added type imports into an `if TYPE_CHECKING:` block

    Note: `from __future__ import annotations` is handled by libcst's
    ApplyTypeAnnotationsVisitor via use_future_annotations=True.
    """

    def __init__(
        self,
        new_from_imports: Dict[str, List[cst.ImportAlias]],
        import_nodes_to_modify: List[cst.ImportFrom],
    ) -> None:
        self.new_from_imports = new_from_imports
        self.import_nodes_to_modify = import_nodes_to_modify
        self._has_type_checking_import = False

    def visit_ImportFrom(self, node: cst.ImportFrom) -> None:
        module = get_full_name_for_node(node.module) if node.module else ""

        if module == "typing":
            if isinstance(node.names, cst.ImportStar):
                self._has_type_checking_import = True
                return
            for alias in node.names:
                if get_full_name_for_node(alias.name) == "TYPE_CHECKING":
                    self._has_type_checking_import = True

    def leave_ImportFrom(
        self, original_node: cst.ImportFrom, updated_node: cst.ImportFrom
    ) -> Union[cst.ImportFrom, cst.RemovalSentinel]:
        """Remove new imports from their original location."""
        if original_node not in self.import_nodes_to_modify:
            return updated_node

        if isinstance(updated_node.names, cst.ImportStar):
            return updated_node

        module = (
            get_full_name_for_node(updated_node.module)
            if updated_node.module
            else ""
        )
        new_names_for_module = self.new_from_imports.get(module, [])
        new_name_strs = {
            get_full_name_for_node(alias.name) for alias in new_names_for_module
        }

        # Keep only the imports that are NOT new (i.e., were present before)
        remaining_aliases = [
            alias
            for alias in updated_node.names
            if get_full_name_for_node(alias.name) not in new_name_strs
        ]

        if not remaining_aliases:
            return cst.RemovalSentinel.REMOVE

        # Rebuild the import with remaining aliases
        return updated_node.with_changes(
            names=_normalize_import_aliases(remaining_aliases)
        )

    def leave_Module(
        self, original_node: cst.Module, updated_node: cst.Module
    ) -> cst.Module:
        """Add TYPE_CHECKING import and TYPE_CHECKING block."""
        if not self.new_from_imports:
            return updated_node

        # Find position to add TYPE_CHECKING import and block (after all imports)
        type_checking_insert_pos = (
            self._find_last_import_position(updated_node.body) + 1
        )

        # Build statements to insert
        statements_to_insert: List[
            Union[cst.SimpleStatementLine, cst.BaseCompoundStatement]
        ] = []

        # Add TYPE_CHECKING import if needed
        if not self._has_type_checking_import:
            type_checking_import = cst.SimpleStatementLine(
                body=[
                    cst.ImportFrom(
                        module=cst.Name("typing"),
                        names=[cst.ImportAlias(name=cst.Name("TYPE_CHECKING"))],
                    )
                ],
                leading_lines=[cst.EmptyLine()],
            )
            statements_to_insert.append(type_checking_import)

        # Build the TYPE_CHECKING block with new imports
        type_checking_block = self._build_type_checking_block()
        if type_checking_block:
            statements_to_insert.append(type_checking_block)

        # Insert the new statements
        final_body = (
            list(updated_node.body[:type_checking_insert_pos])
            + statements_to_insert
            + list(updated_node.body[type_checking_insert_pos:])
        )

        return updated_node.with_changes(body=final_body)

    def _find_last_import_position(
        self,
        body: Sequence[Union[cst.SimpleStatementLine, cst.BaseCompoundStatement]],
    ) -> int:
        """Find the index of the last import statement."""
        last_import_idx = -1
        for i, stmt in enumerate(body):
            if isinstance(stmt, cst.SimpleStatementLine):
                for item in stmt.body:
                    if isinstance(item, (cst.Import, cst.ImportFrom)):
                        last_import_idx = i
        return last_import_idx

    def _build_type_checking_block(self) -> Optional[cst.If]:
        """Build an if TYPE_CHECKING block containing the new imports."""
        if not self.new_from_imports:
            return None

        import_statements: List[cst.SimpleStatementLine] = []

        for module, aliases in sorted(self.new_from_imports.items()):
            normalized_aliases = _normalize_import_aliases(aliases)
            import_from = cst.ImportFrom(
                module=_build_module_attribute(module),
                names=normalized_aliases,
            )
            import_statements.append(cst.SimpleStatementLine(body=[import_from]))

        return cst.If(
            test=cst.Name("TYPE_CHECKING"),
            body=cst.IndentedBlock(body=import_statements),
            leading_lines=[cst.EmptyLine()],
        )


def _build_module_attribute(module_path: str) -> Union[cst.Name, cst.Attribute]:
    """Build a Name or Attribute node from a dotted module path."""
    parts = module_path.split(".")
    if len(parts) == 1:
        return cst.Name(parts[0])

    result: Union[cst.Name, cst.Attribute] = cst.Name(parts[0])
    for part in parts[1:]:
        result = cst.Attribute(value=result, attr=cst.Name(part))
    return result


def _normalize_import_aliases(
    aliases: Sequence[cst.ImportAlias],
) -> Sequence[cst.ImportAlias]:
    """Normalize import aliases by resetting comma separators."""
    if len(aliases) == 1:
        return [aliases[0].with_changes(comma=cst.MaybeSentinel.DEFAULT)]

    normalized = []
    for i, alias in enumerate(aliases):
        if i < len(aliases) - 1:
            normalized.append(
                alias.with_changes(
                    comma=cst.Comma(whitespace_after=cst.SimpleWhitespace(" "))
                )
            )
        else:
            normalized.append(alias.with_changes(comma=cst.MaybeSentinel.DEFAULT))
    return normalized


def apply_pep563_transformation(
    original_module: cst.Module, transformed_module: cst.Module
) -> cst.Module:
    """
    Apply PEP 563 transformation to move new imports into TYPE_CHECKING block.

    Args:
        original_module: The parsed module before type annotations were applied.
        transformed_module: The parsed module after type annotations were applied.

    Returns:
        The transformed module with PEP 563 applied.
    """
    # Gather imports from the original source
    original_gatherer = GatherImportsBeforeTransform()
    original_module.visit(original_gatherer)

    # Identify new imports in the transformed source
    new_import_gatherer = GatherNewImports(
        original_gatherer.module_imports,
        original_gatherer.from_imports,
    )
    transformed_module.visit(new_import_gatherer)

    if not new_import_gatherer.new_from_imports:
        # No new imports to move; libcst handles `from __future__ import annotations`
        # via use_future_annotations=True, so just return the transformed module
        return transformed_module

    # Apply the PEP 563 transformation
    transformer = PEP563Transformer(
        new_import_gatherer.new_from_imports,
        new_import_gatherer.import_nodes_to_modify,
    )
    return transformed_module.visit(transformer)

